fn apply_twice<F: Fn(i64) -> i64>(f: F, x: i64) -> i64 {
    // Apply f to x, then apply f again to the result
    x
}

fn double_twice(input: &str) -> i64 {
    let x: i64 = input.trim().parse().unwrap_or(0);
    apply_twice(|n| n * 2, x)
}

fn even_squares(n: u32) -> Vec<u32> {
    // Use (1..=n).filter(...).map(...).collect()
    vec![]
}

fn even_squares_sum(input: &str) -> u64 {
    let n: u32 = input.trim().parse().unwrap_or(0);
    even_squares(n).iter().map(|&x| x as u64).sum()
}

use std::collections::HashMap;

fn top_n_words(text: &str, n: usize) -> Vec<String> {
    let mut counts: HashMap<String, usize> = HashMap::new();
    for word in text.split_whitespace() {
        *counts.entry(word.to_lowercase()).or_insert(0) += 1;
    }
    let mut pairs: Vec<(String, usize)> = counts.into_iter().collect();
    pairs.sort_by(|a, b| b.1.cmp(&a.1).then(a.0.cmp(&b.0)));
    pairs.into_iter().take(n).map(|(w, _)| w).collect()
}

fn top_words(input: &str) -> String {
    // Parse first token as n, rest as text
    let mut parts = input.splitn(2, ' ');
    let n: usize = parts.next().unwrap_or("0").parse().unwrap_or(0);
    let text = parts.next().unwrap_or("");
    top_n_words(text, n).join(",")
}
